    <nav className="nav">
      <h2 className="nav__titulo">Lucas Cardozo</h2>
      <div className="nav__iconoMenu">
        <span></span>
        <span></span>
        <span></span>
      </div>
      <NavUl />
    </nav>
  );
}

export default Nav;
